import os
import re
from collections import defaultdict, deque

def get_imports_from_package(pkg_path, module_name="go.flipt.io/flipt"):
    """Get imports from files directly in a package (not subdirs)"""
    imports = set()

    if not os.path.isdir(pkg_path):
        return imports

    try:
        for file in os.listdir(pkg_path):
            if file.endswith('.go') and not file.endswith('_test.go'):
                filepath = os.path.join(pkg_path, file)
                try:
                    with open(filepath, 'r') as f:
                        content = f.read()

                        # Find all import statements
                        import_block_pattern = r'import\s*\((.*?)\)'
                        import_single_pattern = r'import\s+"([^"]+)"'

                        # Find all import blocks
                        for match in re.finditer(import_block_pattern, content, re.DOTALL):
                            block = match.group(1)
                            for line in block.split('\n'):
                                line = line.strip()
                                if line and not line.startswith('//'):
                                    quoted = re.search(r'"([^"]+)"', line)
                                    if quoted:
                                        imports.add(quoted.group(1))

                        # Find single imports
                        for match in re.finditer(import_single_pattern, content):
                            imports.add(match.group(1))
                except:
                    pass
    except:
        pass

    return imports

workspace = "/workspace"
module_name = "go.flipt.io/flipt"

# Find all packages
all_packages = set()
for root, dirs, files in os.walk(workspace):
    if any(x in root for x in ['vendor', '.git', 'ui', 'examples', 'build', 'bin', '_tools', '.vscode', '.devcontainer', 'logos']):
        continue

    go_files = [f for f in files if f.endswith('.go') and not f.endswith('_test.go')]
    if go_files:
        rel_path = os.path.relpath(root, workspace)
        if rel_path.startswith('internal') or rel_path.startswith('rpc') or rel_path.startswith('errors') or rel_path.startswith('config') or rel_path.startswith('core'):
            all_packages.add(rel_path)

# Build complete dependency graph
deps_graph = {}
for pkg in sorted(all_packages):
    pkg_dir = os.path.join(workspace, pkg)
    all_imports = get_imports_from_package(pkg_dir, module_name)
    internal_imports = set()
    for imp in all_imports:
        if imp.startswith(module_name + "/"):
            rel_imp = imp[len(module_name)+1:]
            internal_imports.add(rel_imp)
    deps_graph[pkg] = internal_imports

# Find all reachable packages from evaluation server
eval_pkg = "internal/server/evaluation"
reachable = set()
to_visit = [eval_pkg]
visited = set()

while to_visit:
    pkg = to_visit.pop(0)
    if pkg in visited:
        continue
    visited.add(pkg)
    if pkg in all_packages or pkg in deps_graph:
        reachable.add(pkg)

    for dep in deps_graph.get(pkg, set()):
        if dep not in visited:
            to_visit.append(dep)

print(f"Starting package: {eval_pkg}")
print(f"Total reachable packages: {len(reachable)}")
print()

# Filter deps_graph to only reachable packages
filtered_graph = {}
for pkg in reachable:
    if pkg in deps_graph:
        filtered_graph[pkg] = deps_graph[pkg] & reachable
    else:
        filtered_graph[pkg] = set()

# Print dependencies
print("Reachable dependency graph:")
for pkg in sorted(filtered_graph.keys()):
    if filtered_graph[pkg]:
        print(f"{pkg}:")
        for dep in sorted(filtered_graph[pkg]):
            print(f"  -> {dep}")
    else:
        print(f"{pkg}: (leaf)")
print()

# Topological sort using Kahn's algorithm
in_degree = defaultdict(int)
graph = defaultdict(set)

# Build the reverse graph
for pkg in filtered_graph:
    if pkg not in in_degree:
        in_degree[pkg] = 0
    for dep in filtered_graph[pkg]:
        graph[dep].add(pkg)  # dep must come before pkg
        in_degree[pkg] += 1

# Find nodes with in-degree 0
queue = deque([pkg for pkg in filtered_graph if in_degree[pkg] == 0])
topo_order = []

while queue:
    # Sort to make deterministic
    current = sorted(list(queue))
    queue.clear()

    for pkg in current:
        topo_order.append(pkg)

        # For each package that depends on this one
        for dependent in sorted(graph[pkg]):
            in_degree[dependent] -= 1
            if in_degree[dependent] == 0:
                queue.append(dependent)

if len(topo_order) == len(filtered_graph):
    print(f"Topological sort successful! ({len(topo_order)} packages)")
    print()
    for i, pkg in enumerate(topo_order, 1):
        print(f"{i}. {pkg}")

    # Write to JSON
    import json
    result = {
        "evaluation_server": eval_pkg,
        "total_packages": len(topo_order),
        "packages": topo_order
    }

    with open("/workspace/submission.json", "w") as f:
        json.dump(topo_order, f, indent=2)

    print(f"\n✓ Written to /workspace/submission.json")
else:
    print(f"Error: Could not topologically sort!")
    print(f"Processed {len(topo_order)} out of {len(filtered_graph)} packages")
    print(f"\nRemaining packages with non-zero in-degree:")
    for pkg in sorted(filtered_graph.keys()):
        if in_degree[pkg] > 0:
            print(f"  {pkg}: {in_degree[pkg]}")
